INSERT INTO `v1_839019bded3a588804abd96bc887578bbc04b1f2a9c1da3840a16948faa64999` VALUES (10, 302, 13020023, "", 11, "", "", "ふむ…これは僥倖\nかくなる上は再び\n潜航してみるか…", "", "", 111031);
INSERT INTO `v1_839019bded3a588804abd96bc887578bbc04b1f2a9c1da3840a16948faa64999` VALUES ("", 302, 13020024, "", 91, "", "", "", "", "", 0);
